const SERVER_URL = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
const FARM_ID = env.get('FARM_ID') || 'farm_001';
const HOUSE_ID = env.get('HOUSE_ID') || 'house_001';
const API_KEY = env.get('SENSOR_API_KEY') || '';

// operationMode가 아직 설정 안 된 경우 (재시작 직후)
// serverOnline도 체크하여 기본값 결정
const serverOnline = global.get('serverOnline');
const operationMode = global.get('operationMode') || (serverOnline === true ? 'online' : 'offline');

if (operationMode === 'online') {
    // 온라인: 서버에서 설정 가져오기
    msg.url = `${SERVER_URL}/api/config/${HOUSE_ID}?farmId=${FARM_ID}`;
    msg.method = 'GET';
    msg.headers = { 'Content-Type': 'application/json', 'x-api-key': API_KEY };
    node.status({ fill: 'blue', shape: 'dot', text: '온라인: 서버 config 요청' });
    return [msg, null, null]; // 출력1: HTTP Request
} else {
    // 오프라인: global 캐시 → SQLite 캐시
    const cachedConfig = global.get('houseConfig');
    if (cachedConfig) {
        msg.config = cachedConfig;
        node.status({ fill: 'yellow', shape: 'dot', text: '오프라인: global 캐시 사용' });
        return [null, msg, null]; // 출력2: 센서 수집으로
    } else {
        // SQLite config_cache에서 로드
        msg.topic = 'SELECT config_json FROM config_cache ORDER BY version DESC LIMIT 1';
        node.status({ fill: 'yellow', shape: 'ring', text: '오프라인: SQLite 캐시 조회' });
        return [null, null, msg]; // 출력3: SQLite 조회
    }
}

if (msg.statusCode !== 200) {
    const cachedConfig = global.get('houseConfig');
    if (cachedConfig) {
        node.warn('⚠️ 서버 응답 실패, 캐시된 설정 사용');
        msg.config = cachedConfig;
        return [msg, null];
    }
    node.error('❌ 서버 응답 실패, 캐시도 없음');
    return [null, null];
}

const response = msg.payload;
if (!response.success) {
    node.error('설정 오류: ' + (response.error || 'unknown'));
    return [null, null];
}

const config = response.data;

// global 캐시 갱신
const cachedConfig = global.get('houseConfig');
const cachedVersion = cachedConfig ? cachedConfig.configVersion : 0;

if (!cachedConfig || config.configVersion > cachedVersion) {
    node.warn('📋 설정 업데이트: v' + cachedVersion + ' → v' + config.configVersion);
    global.set('houseConfig', config);

    // SQLite에도 캐시 저장 (위치 파라미터)
    const cacheMsg = {
        topic: 'INSERT OR REPLACE INTO config_cache (id, farm_id, house_id, config_json, version, updated_at) VALUES (1, $1, $2, $3, $4, $5)',
        payload: [
            config.farmId || 'farm_001',
            config.houseId || (config.houses && config.houses[0] ? config.houses[0].houseId : 'house_001'),
            JSON.stringify(config),
            config.configVersion || 1,
            new Date().toISOString()
        ]
    };
    msg.config = config;
    return [msg, cacheMsg];
}

msg.config = config;
return [msg, null];

const rows = msg.payload || [];

if (rows.length > 0 && rows[0].config_json) {
    try {
        const config = JSON.parse(rows[0].config_json);
        global.set('houseConfig', config);
        msg.config = config;
        node.warn('📋 SQLite에서 config 복원 완료');
        node.status({ fill: 'green', shape: 'dot', text: 'SQLite config 복원' });
        return msg;
    } catch (e) {
        node.error('❌ config JSON 파싱 실패: ' + e.message);
    }
}

node.error('❌ SQLite config_cache도 비어있음 - 서버에 1회 접속 필요');
node.status({ fill: 'red', shape: 'dot', text: 'config 없음!' });
return null;

const config = msg.config || global.get('houseConfig');

if (!config) {
    node.error('❌ config 없음, 수집 중단');
    return null;
}

// 하우스별 센서 수집 (첫 번째 하우스 또는 config 직접 참조)
let sensors, farmId, houseId;

if (config.houses && config.houses.length > 0) {
    const house = config.houses[0];
    sensors = house.sensors || [];
    farmId = config.farmId;
    houseId = house.houseId;
} else if (config.sensors) {
    sensors = config.sensors;
    farmId = config.farmId;
    houseId = config.houseId;
} else {
    node.error('❌ 센서 설정 없음');
    return null;
}

const enabledSensors = sensors.filter(s => s.enabled);
if (enabledSensors.length === 0) {
    node.warn('⚠️ 활성 센서 없음');
    return null;
}

// 센서 데이터 읽기 (시뮬레이션 - 실제 GPIO 연결 시 여기를 수정)
const sensorData = {};
for (const sensor of enabledSensors) {
    try {
        let value;
        switch (sensor.sensorId) {
            case 'temp_001':
                value = parseFloat((Math.random() * 10 + 20).toFixed(1));
                break;
            case 'humidity_001':
                value = parseFloat((Math.random() * 20 + 50).toFixed(1));
                break;
            case 'co2_001':
                value = parseInt(Math.random() * 200 + 400);
                break;
            default:
                if (sensor.type === 'number') {
                    const min = sensor.min !== null ? sensor.min : 0;
                    const max = sensor.max !== null ? sensor.max : 100;
                    value = parseFloat((Math.random() * (max - min) + min).toFixed(sensor.precision || 1));
                } else if (sensor.type === 'boolean') {
                    value = Math.random() > 0.5;
                } else {
                    value = 'OK';
                }
        }
        sensorData[sensor.sensorId] = value;
    } catch (e) {
        node.error('센서 읽기 실패: ' + sensor.sensorId + ' - ' + e.message);
        sensorData[sensor.sensorId] = null;
    }
}

msg.payload = {
    farmId: farmId,
    houseId: houseId,
    data: sensorData,
    timestamp: new Date().toISOString(),
    deviceInfo: {
        deviceId: env.get('DEVICE_ID') || 'rpi_001',
        ip: '192.168.137.86',
        version: '2.0.0-offline'
    }
};

node.warn('📡 센서 수집: ' + Object.keys(sensorData).join(', '));
node.status({ fill: 'green', shape: 'dot', text: Object.keys(sensorData).length + '개 센서 수집' });

return msg;

const { farmId, houseId, data, timestamp } = msg.payload;
const ts = timestamp || new Date().toISOString();

// 센서 데이터 수집
const entries = Object.entries(data).filter(([k, v]) => v !== null && v !== undefined);

if (entries.length === 0) {
    node.warn('⚠️ 저장할 데이터 없음');
    return null;
}

// 위치 파라미터 쿼리로 개별 INSERT (센서별 msg 배열)
// node-red-node-sqlite msg.topic 모드: msg.payload 배열 + $N 파라미터 사용
const messages = entries.map(([sensorId, value]) => ({
    topic: 'INSERT INTO sensor_data (timestamp, farm_id, house_id, sensor_id, value, synced) VALUES ($1, $2, $3, $4, $5, 0)',
    payload: [ts, farmId, houseId, sensorId, value],
    _insertTimestamp: ts,
    _sensorCount: entries.length,
    _isLast: false,
    _originalPayload: msg.payload
}));

// 마지막 메시지에 표시 (모드 분기용)
const srvOnline = global.get('serverOnline');
const opMode = global.get('operationMode') || (srvOnline === true ? 'online' : 'offline');
messages[messages.length - 1]._isLast = true;
messages[messages.length - 1]._operationMode = opMode;

node.warn('💾 SQLite INSERT: ' + entries.length + '건');
return [messages];

// 마지막 INSERT 메시지만 처리 (나머지는 통과)
if (!msg._isLast) { return null; }

const serverOnline = global.get('serverOnline');
const mode = msg._operationMode || global.get('operationMode') || (serverOnline === true ? 'online' : 'offline');

// 원본 payload 복원 (서버 전송용)
if (msg._originalPayload) { msg.payload = msg._originalPayload; }

if (mode === 'online') {
    const SERVER_URL = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
    const API_KEY = env.get('SENSOR_API_KEY') || '';

    msg.url = SERVER_URL + '/api/sensors/collect';
    msg.method = 'POST';
    msg.headers = { 'Content-Type': 'application/json', 'x-api-key': API_KEY };

    node.status({ fill: 'green', shape: 'dot', text: '온라인: SQLite ✓ + 서버 전송' });
    return [msg, null];
} else {
    node.warn('📴 오프라인: SQLite만 저장 (synced=0)');
    node.status({ fill: 'yellow', shape: 'dot', text: '오프라인: SQLite ✓ (' + msg._sensorCount + '건)' });
    msg.payload = '오프라인 저장 완료: ' + msg._sensorCount + '건';
    return [null, msg];
}

if (msg.statusCode === 201 || msg.statusCode === 200) {
    node.warn('✅ 서버 전송 성공 → synced=1');

    const syncMsg = {
        topic: 'UPDATE sensor_data SET synced = 1 WHERE timestamp = $1 AND synced = 0',
        payload: [msg._insertTimestamp]
    };

    node.status({ fill: 'green', shape: 'dot', text: '서버 전송 ✓ + synced' });
    return [syncMsg, msg];
} else {
    node.warn('⚠️ 서버 전송 실패 (' + msg.statusCode + '): synced=0 유지');
    node.status({ fill: 'yellow', shape: 'ring', text: '전송 실패 (synced=0)' });
    return [null, msg];
}
